// src/store/slices/productsSlice.js

import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import { BASE_URL } from '../../utils/api'; 
// Импорт функции для применения фильтров на стороне клиента
import { applyFilters } from '../../utils/filterUtils'; 

// 🚨 ВАЖНО: Мы сохраним все данные, а затем будем фильтровать их на клиенте, 
// чтобы не вызывать постоянно API при смене фильтров.

// --- 1. THUNK: Загрузка всех продуктов (/products/all) ---
export const fetchAllProducts = createAsyncThunk(
  'products/fetchAllProducts',
  async (_, { rejectWithValue }) => {
    try {
      // ИСПОЛЬЗУЕМ API-МАРШРУТ ДЛЯ ВСЕХ ТОВАРОВ
      const response = await fetch(`${BASE_URL}/products/all`); 

      if (!response.ok) {
        throw new Error('Failed to fetch all products.');
      }

      return await response.json(); 

    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

// --- 2. THUNK: Загрузка продуктов по ID категории (/categories/:id) ---
// Т.к. вы используете этот Thunk для категорий, мы оставляем его.
export const fetchProductsByCategory = createAsyncThunk(
  'products/fetchProductsByCategory',
  async (categoryId, { rejectWithValue }) => {
    try {
      // ИСПОЛЬЗУЕМ API-МАРШРУТ ДЛЯ КАТЕГОРИИ
      const response = await fetch(`${BASE_URL}/categories/${categoryId}`); 

      if (!response.ok) {
        throw new Error('Failed to fetch products for category.');
      }

      const data = await response.json(); 
      // Возвращаем ВСЕ полученные данные.
      return data; 

    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

// --- 3. НОВЫЙ THUNK: Загрузка скидочных товаров (/sale) ---
export const fetchDiscountedProducts = createAsyncThunk(
  'products/fetchDiscountedProducts',
  async (_, { rejectWithValue }) => {
    try {
      // ИСПОЛЬЗУЕМ API-МАРШРУТ ДЛЯ СКИДОЧНЫХ ТОВАРОВ
      const response = await fetch(`${BASE_URL}/products/sale`); 

      if (!response.ok) {
        throw new Error('Failed to fetch discounted products.');
      }

      return await response.json(); 

    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);


// --- ИНИЦИАЛИЗАЦИЯ СОСТОЯНИЯ ---
const initialState = {
  // Список товаров, отображаемых после фильтрации
  list: [], 
  // Полный список товаров, полученный с сервера (для дальнейшей фильтрации)
  rawList: [],
  selectedProduct: null, 
  status: 'idle', 
  detailsStatus: 'idle', 
  error: null,
  filters: { 
    priceFrom: '', // Переименовано для ясности
    priceTo: '',   // Переименовано для ясности
    discount: false, // Использовать camelCase для JavaScript
    sortBy: 'default', 
  },
  // Флаг, указывающий, загружали ли мы сейчас только товары со скидкой
  isDiscountPage: false,
};


// --- СОЗДАНИЕ СЛАЙСА ---
const productsSlice = createSlice({
  name: 'products',
  initialState,
  reducers: {
    setProductsFilter: (state, action) => {
      // Обновляем фильтры
      state.filters = { ...state.filters, ...action.payload };

      // 🚨 ВАЖНОЕ ИЗМЕНЕНИЕ: Применяем фильтры сразу же при их изменении
      // (Предполагая, что у вас есть функция applyFilters или вы ее реализуете)
      state.list = applyFilters(state.rawList, state.filters); 
    },
    // Редьюсер для очистки сырого списка при выходе из категории/скидок
    clearRawList: (state) => {
        state.rawList = [];
        state.list = [];
        state.status = 'idle';
        state.isDiscountPage = false;
    }
  },
  extraReducers: (builder) => {
    // --- Вспомогательная функция для обработки Pending ---
    const handlePending = (state) => {
      state.status = 'loading';
      state.error = null;
    };

    // --- Вспомогательная функция для обработки Fulfilled ---
    const handleFulfilled = (state, rawData, isDiscount) => {
        state.status = 'succeeded';
        state.isDiscountPage = isDiscount;
        state.rawList = rawData;
        // Применяем фильтры к полученным данным
        state.list = applyFilters(state.rawList, state.filters);
    };

    // --- fetchAllProducts ---
    builder
      .addCase(fetchAllProducts.pending, handlePending)
      .addCase(fetchAllProducts.fulfilled, (state, action) => {
          // data — это массив продуктов [product1, product2, ...]
          handleFulfilled(state, action.payload, false);
      })
      .addCase(fetchAllProducts.rejected, (state, action) => {
          state.status = 'failed';
          state.error = action.payload;
      })

    // --- fetchDiscountedProducts ---
      .addCase(fetchDiscountedProducts.pending, handlePending)
      .addCase(fetchDiscountedProducts.fulfilled, (state, action) => {
          // data — это массив продуктов [product1, product2, ...]
          handleFulfilled(state, action.payload, true);
      })
      .addCase(fetchDiscountedProducts.rejected, (state, action) => {
          state.status = 'failed';
          state.error = action.payload;
      })


    // --- fetchProductsByCategory ---
      .addCase(fetchProductsByCategory.pending, handlePending)
      .addCase(fetchProductsByCategory.fulfilled, (state, action) => {
          // 🚨 ИСПРАВЛЕНИЕ: Бэкенд возвращает { category: { id, products: [...] } }
          const productsData = action.payload.category?.products || [];
          handleFulfilled(state, productsData, false);
      })
      .addCase(fetchProductsByCategory.rejected, (state, action) => {
          state.status = 'failed';
          state.error = action.payload;
      })

      // --- fetchProductById (без изменений) ---
      .addCase(fetchProductById.pending, (state) => {
        state.detailsStatus = 'loading';
        state.selectedProduct = null;
        state.error = null;
      })
      .addCase(fetchProductById.fulfilled, (state, action) => {
        state.detailsStatus = 'succeeded';
        state.selectedProduct = action.payload;
      })
      .addCase(fetchProductById.rejected, (state, action) => {
        state.detailsStatus = 'failed';
        state.error = action.payload;
      });
  },
});

export const { setProductsFilter, clearRawList } = productsSlice.actions; 
export default productsSlice.reducer;
